import { useState, useEffect } from 'react'
import Section from './_Section'
import { createMarkup, createGradientElement } from '../../helpers/markup'
import ButtonEl from '../helpers/ctas/Button'
import { PlusIcon, MinusIcon } from '@heroicons/react/24/solid'
import themeConfig from '../../../theme.config'
import TitleBlock from '../helpers/TitleBlock'
import { addBgImageClass, lightOrDark, transformPaddingToTailwind } from '../../helpers/style'


function MemberPortalEvents(props) {
  const [backgroundColor, setBackgroundColor] = useState('transparent')
  const [gradientColor, setgradientColor] = useState('#fff')
  const componentPadding = transformPaddingToTailwind(props.componentPadding)

  useEffect(() => {
    const bgColor = props.cardBackgroundColour.replace('#', '')
    const fgColor = props.imageGradientColour.replace('#', '')
    setBackgroundColor((prevState) => (bgColor ? `#${bgColor}` : prevState))
    setgradientColor((prevState) => (fgColor ? `#${fgColor}` : prevState))
  }, [])

  let eventCount = 0

  return (
    <Section type="memberPortalEvents" outerClass={componentPadding} {...props} sectionTitle={false}>
      <div className={`mb-16 w-2/3 mx-auto text-center`}>
        <TitleBlock {...props} title={`<h1 class="banner text-center">Welcome${props.allData.memberPortal?.name ? `, ${props.allData.memberPortal.name}` : ''}</h1>`} />
      </div>
      <div class={`mx-6`}>
        {props.title && (
          <div className='text-highlight-500' dangerouslySetInnerHTML={createMarkup(props.title)} />
        )}
        <div className='w-full relative overflow-hidden'>
          <div className='flex flex-nowrap gap-8'>
            {props.events?.length && props.events?.map((memberEvent, idx) => (
              <>
                {memberEvent.functions && memberEvent.functions?.length && memberEvent.functions?.map((memberFunction, fidx) => {
                  if (eventCount > 2) {
                    return (<></>)
                  }
                  eventCount++
                  return (
                    <div className='mb-4 basis-[40%] shrink-0'>
                      <div className='flex gap-4'>
                        {memberFunction.category && (
                          <span className='category'>{memberFunction.category}</span>
                        )}
                        <span className='text-dark-200'>
                          {new Date(memberFunction.startDateTime).toLocaleDateString()}
                          {new Date(memberFunction.startDateTime).toLocaleDateString() !== new Date(memberFunction.endDateTime).toLocaleDateString() ? (<span dangerouslySetInnerHTML={createMarkup(`&nbsp;&mdash;&nbsp;${new Date(memberFunction.endDateTime).toLocaleDateString()}`)}></span>) : ''}
                        </span>
                      </div>
                      <h3 className="text-highlight-500 text-event">{memberFunction.name}</h3>
                      {memberFunction.description && (
                        <p className='line-clamp-3 text-dark-200' dangerouslySetInnerHTML={createMarkup(memberFunction.description)} />
                      )}
                    </div>
                  )
                })
                }
              </>
            ))}
          </div>
        </div>
      </div>
    </Section>
  )
}
export default MemberPortalEvents