import { useState, useEffect, createElement } from 'react'
import Section from './_Section'
import ButtonEl from '../helpers/ctas/Button'
import { transformPaddingToTailwind } from '../../helpers/style'
import TitleBlock from '../helpers/TitleBlock'
import LoginForm from '../helpers/LoginForm'
import { createMarkup } from '../../helpers/markup'

function RegisterForm(props) {
  const [antiForgery, setAntiForgery] = useState(null)
  
  useEffect(() => {
    const htmlElement = document.querySelector(`[name='__RequestVerificationToken']`)
    setAntiForgery(() => htmlElement.value)
  }, [])

  return (
    <div className={`mb-8 pb-8 md:pr-12 border-b border-[#C6C6C6]`} >
      {props.registrationFormTitle && (
        <div class={`container mb-12 mx-auto ${props.componentPadding.mid} `}>
          <TitleBlock headingClass={`w-full `} {...props} title={props.registrationFormTitle} description={props.noteCopy}  />
        </div>
      )}
      <form action="/umbraco/surface/member/register" method="post">
        <div className='mb-6'>
          <label className={`block mb-4 text-sm`} htmlFor='ipaFirstname'>{props.firstNameLabel}</label>
          <input id="ipaFirstname" name="firstname" className={`rounded-full block w-full`} type="text" />
        </div>
        <div className='mb-6'>
          <label className={`block mb-4 text-sm`} htmlFor='ipaLastname'>{props.lastNameLabel}</label>
          <input id="ipaLastname" name="lastname" className={`rounded-full block w-full`} type="text" />
        </div>
        <div className='mb-6'>
          <label className={`block mb-4 text-sm`} htmlFor='ipaRegEmail'>{props.registrationEmailAddressLabel}</label>
          <input id="ipaRegEmail" name="email" autoComplete='email' className={`rounded-full block w-full`} type="email" />
        </div>
        <div className='mb-6'>
          <label className={`block mb-4 text-sm`} htmlFor='ipaRegPass'>{props.passwordLabel}</label>
          <input id="ipaRegPass" name="password" className={`rounded-full block w-full`} autoComplete="current-password" type="password" />
        </div>
        <div className='mb-6'>
          <label className={`block mb-4 text-sm`} htmlFor='ipaConfirmPass'>{props.reenterPasswordLabel}</label>
          <input id="ipaConfirmPass" name="confirm" className={`rounded-full block w-full`} type="password" />
        </div>
        <div className='mb-6 flex'>
          <input id="ipaTerms" name="terms" className={`rounded inline mr-6 flex-shrink-1`} type="checkbox" />
          <label className={`inline mb-4 text-sm`} htmlFor='ipaTerms' dangerouslySetInnerHTML={createMarkup(props.termsAndConditionsLabel)}></label>
        </div>
        <input type="hidden" name="redirectUrl" value={props.allData.memberPortalLandingPage} required />
        <input type="hidden" name="__RequestVerificationToken" value={antiForgery} required />

        <div className='flex justify-between'>
          <ButtonEl
            disabled={!!antiForgery}
            theme={'primary'}
            className="!justify-center mt-6 ml-auto uppercase text-sm"
            label={props.registerFormButtonLabel}
            type={'submit'}
          />
        </div>
      </form>
    </div>
  )
}

function Register(props) {
  const [formType, setFormType] = useState('login')
  const componentPadding = transformPaddingToTailwind(props.componentPadding)

  return (
    <Section type="login" outerClass={componentPadding} sectionTitle={false} {...props} >
      <div className=''>
        <div className={`mb-8 `}>
          <RegisterForm {...props} componentPadding={componentPadding} />
        </div>
        <div className={`mb-8 `}>
          <LoginForm {...props} componentPadding={componentPadding} titleOverride={'Already have an account?'} noDecorator={true} />
        </div>
      </div>
    </Section>
  )
}

export default Register