import { useState, useEffect } from 'react'
import ButtonEl from '../helpers/ctas/Button'
import TitleBlock from '../helpers/TitleBlock'


function LoginForm(props) {
    const [antiForgery, setAntiForgery] = useState(null)
    
    useEffect(() => {
      const htmlElement = document.querySelector(`[name='__RequestVerificationToken']`)
      setAntiForgery(() => htmlElement.value)
    }, [])
  
    return (
      <div className={`mb-8 pb-8 ${!props.noDecorator ? 'md:pb-[0] md:pr-12 md:border-r border-b md:border-b-[0] border-[#C6C6C6]' : ''}`} >
        <div class={`container mb-12 mx-auto ${props.componentPadding.mid} `}>
        <TitleBlock headingClass={`w-full `}  {...props} description={!props.titleOverride ? props.description : ''} title={`<h2 class="banner">${props.titleOverride ? props.titleOverride : props.loginFormTitle}</h1>`} />
        </div>
        <form action="/umbraco/surface/member/login" method="post">
          <div className='mb-6'>
            <label className={`block mb-4 text-sm`} htmlFor='ipaLogin'>{props.usernameLabel ? props.usernameLabel : props.registrationEmailLabel ? props.registrationEmailLabel : 'Email'}</label>
            <input id="ipaLogin" name="email" autoComplete='email' className={`rounded-full block w-full`} type="text" />
          </div>
          <div className='mb-6'>
            <label className={`block mb-4 text-sm`} htmlFor='ipaPass'>{props.passwordLabel}</label>
            <input id="ipaPass" name="password"  autoComplete='current-password' className={`rounded-full block w-full`} type='password' />
          </div>
          <input type="hidden" name="redirectUrl" value={props.allData.memberPortalLandingPage} required />
          <input type="hidden" name="__RequestVerificationToken" value={antiForgery} required />
          <div className='flex justify-between'>
            {props.forgotPasswordLink && props.forgotPasswordLink !== null && (
              <a href={props.forgotPasswordLink}>Forgot your password?</a>
            )
  
            }
            <ButtonEl
              theme={'primary'}
              className="!justify-center mt-6 ml-auto uppercase text-sm"
              label={props.loginButtonLabel ? props.loginButtonLabel : 'Login'}
              type={'submit'}
            />
          </div>
        </form>
      </div>
    )
  }

  export default LoginForm