import { createMarkup } from '../../helpers/markup'
import StickyFooter from './StickyFooter'
import themeConfig from '../../../theme.config'
import BackToTop from './BackToTop'
import { lightOrDark } from '../../helpers/style'
import Logo from './Logo'


function Footer(props) {
  const bgSplit = themeConfig.settings.nav.footer.base.split('-')

  return (
    <>
      <footer
        style={{
          '--bg-color': themeConfig.settings.nav.footer.base ?? '#fff',
          '--light-or-dark': lightOrDark(themeConfig.settings.nav.footer.base),
        }}
        className={`px-6 py-16 grid grid-rows-[1fr, 1fr] grid-cols-[1fr] md:grid-cols-[1fr,2fr] gap-8  bg-[color:var(--bg-color)] text-${lightOrDark(themeConfig.settings.nav.footer.base)}`}
      >
        <div className={``}>
          <Logo deskLogo={props.deskLogo} mobLogo={props.mobLogo} />

          {props.footerDescription && (
            <div className="max-w-[590px] flex items-start  pt-2">
              <div data-rte="true" dangerouslySetInnerHTML={createMarkup(props.footerDescription)} />
            </div>
          )}
          {/* {props.footerDisclaimerText && (
            <div className="max-w-2xl mx-auto text-balance text-xs flex items-start  pt-2">
              <div data-rte="true" dangerouslySetInnerHTML={createMarkup(props.footerDisclaimerText)} />
            </div>
          )} */}
          {props.socialMediaLinks?.length ? (
            <ul className="flex w-3/5 gap-4 my-8 justify-start">
              {props.socialMediaLinks?.map((link, j) => (
                <li key={j}>
                  <a
                    href={link.link?.url}
                    target="_blank"
                    title={link.link?.name}
                    className="block w-[24px] border-b-2 transition-all duration-500 border-transparent hover:border-[currentColor] pb-1 group"
                  >
                    <img
                      className="w-full h-auto group-hover:scale-[1.1] transition-all duration-500"
                      alt=""
                      src={link.linkImage?.src}
                    />
                    <span class="sr-only">{link.link?.name}</span>
                  </a>
                </li>
              ))}
            </ul>
          ) : null}

        </div>
        {props.footerNavigationItems?.length > 0 && (
          <>
            <div className="footer-nav grid grid-cols-2  md:flex md:flex-wrap mb-8 justify-around gap-12">
              {props.footerNavigationItems.map((col, idx) => (
                <nav className="basis-full lg:basis-auto" aria-label={col.title ?? `Footer nav column ${idx + 1}`}>
                  {col.title && <h3 className="text-xl">{col.title}</h3>}
                  <ul>
                    {col.footerNavigationItems?.length > 0 &&
                      col.footerNavigationItems?.map((link, j) => (
                        <>
                          {link.url && (
                            <li data-rte={themeConfig.settings.nav.footer.inheritLinkStyle.toString()}>
                              <a
                                key={`footer-nav-item-${j}`}
                                // className={`hover:underline underline-offset-8 `}
                                className={`
                                  ${j < 1 ? 'font-bold text-light' : 'font-normal text-light '} 
                                  ${themeConfig.settings.nav.footer.inheritLinkStyle
                                    ? ''
                                    : `hover:underline underline-offset-8 hover:text-${lightOrDark(themeConfig.settings.nav.footer.base)}-500-hover`
                                  }`}
                                href={link.url}
                                target={link.target ? link.target : '_self'}
                              >
                                {link.label}
                              </a>
                            </li>
                          )}
                        </>
                      ))}
                  </ul>
                </nav>
              ))}
            </div>
            <div className="max-w-2xl text-left text-xs ">
              &copy; Copyright {new Date().getFullYear()}{' '}
              <div data-rte="true" dangerouslySetInnerHTML={createMarkup(props.copyrightText)} />
            </div>
          </>
        )}
        <BackToTop />
      </footer>
      {!props.disableSticky && (props.stickyNavPrimary || props.stickyNavSecondary) && <StickyFooter {...props} />}
    </>
  )
}

export default Footer
