import { useState, useEffect, createElement } from 'react'
import Section from './_Section'
import { createMarkup } from '../../helpers/markup'
import ButtonEl from '../helpers/ctas/Button'
import { transformPaddingToTailwind } from '../../helpers/style'
import TitleBlock from '../helpers/TitleBlock'
import LoginForm from '../helpers/LoginForm'


function Login(props) {
  const componentPadding = transformPaddingToTailwind(props.componentPadding)

  return (
    <Section type="login" outerClass={componentPadding} {...props}>
      <div className='grid grid-cols-1  md:grid-cols-2'>
        <LoginForm {...props} componentPadding={componentPadding} />
        <div className={`mb-8 md:pl-12`}>
          {props.registrationPanelTitle && (
            <div class={`container mb-12 mx-auto ${componentPadding.mid} `}>
              <TitleBlock headingClass={`w-full `}  {...props} title={`<h2 class="banner">${props.registrationPanelTitle}</h1>`} />
            </div>
          )}
          {props.registrationContent && (
            <div data-rte="true" dangerouslySetInnerHTML={createMarkup(props.registrationContent)}></div>
          )}
          <div className='flex justify-end'>
            <ButtonEl
              link={{
                url: '/member-portal/register',
                target: '_self',
                label: props.registerButtonLabel,
              }}
              theme={'primary'}
              className="!justify-center mt-6 ml-auto uppercase text-sm"
            />
          </div>
        </div>
      </div>
    </Section>
  )
}

export default Login