import Logo from './Logo'
import MobileNav from './MobileNav'
import Search from './Search'
import CtaDropDown from './CTA'
import MainNav from './MainNav'

function Header(props) {
  return (
    <header className={` relative`}>
      {props.children}
      <div className="px-6 mx-auto h-full flex justify-between no-wrap items-stretch  sm:px-8">
        <Logo deskLogo={props.deskLogo} mobLogo={props.mobLogo} />
        {!props.res.hideMegamenu && <MainNav {...props} nav={props.nav} type="desktop" />}
        <Search {...props} />
        {props.ctas && <CtaDropDown {...props} type={'button'} variant="divider" />}
        {!props.res.hideMegamenu && <MobileNav {...props} nav={props.nav} type="mobile" />}
      </div>
    </header>
  )
}

export default Header
